SELECT c.id, c.site_id, s.title AS site_title, c.user_id, u.username, c.guest_name, c.guest_email, c.guest_url, c.content, c.parent_id, c.status, c.create_time FROM site_comment c LEFT JOIN site s ON c.site_id = s.id LEFT JOIN sys_user u ON c.user_id = u.id
c.parent_id IS NULL
AND c.site_id = #{dto.siteId}
AND c.status = #{dto.status}
AND (c.content LIKE CONCAT('%', #{dto.keyword}, '%') OR c.guest_name LIKE CONCAT('%', #{dto.keyword}, '%'))
ORDER BY c.create_time DESC

SELECT c.id, c.site_id, s.title AS site_title, c.user_id, u.username, c.guest_name, c.guest_email, c.guest_url, c.content, c.parent_id, c.status, c.create_time FROM site_comment c LEFT JOIN site s ON c.site_id = s.id LEFT JOIN sys_user u ON c.user_id = u.id WHERE c.parent_id IN
#{pid}
ORDER BY c.create_time ASC
